exercises.solution_code:
#include <iostream>
#include <format>

class Rectangle {
    int m_width;
    int m_height;
    const int m_area;

public:
    Rectangle(int width, int height)
        : m_width{width}, m_height{height}, m_area{width * height}
    {}

    void print() const {
        std::cout << std::format("Width: {}\n", m_width);
        std::cout << std::format("Height: {}\n", m_height);
        std::cout << std::format("Area: {}\n", m_area);
    }
};

int main() {
    int w{}, h{};
    std::cin >> w >> h;

    Rectangle rect{w, h};
    rect.print();

    return 0;
}

