exercises.solution_code:
#include <iostream>
#include <format>
#include <string>

class BankAccount {
    std::string m_owner;
    const double m_openingBalance;
    double m_balance{0.0};

public:
    BankAccount(const std::string& owner, double openingBalance)
        : m_owner{owner}, m_openingBalance{openingBalance}, m_balance{openingBalance}
    {}

    void deposit(double amount) {
        m_balance += amount;
    }

    void print() const {
        std::cout << std::format("Owner: {}\n", m_owner);
        std::cout << std::format("Opening balance: {:.2f}\n", m_openingBalance);
        std::cout << std::format("Balance after deposit: {:.2f}\n", m_balance);
    }
};

int main() {
    std::string name{};
    double opening{}, amount{};
    std::cin >> name >> opening >> amount;

    BankAccount account{name, opening};
    account.deposit(amount);
    account.print();

    return 0;
}
